package picod

import (
	"context"
	"crypto/rsa"
	"crypto/x509"
	"encoding/base64"
	"encoding/pem"
	"fmt"
	"io"
	"mime"
	"net/http"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
	"k8s.io/klog/v2"
)

type Server struct {
	config     *Config
	router     *gin.Engine
	httpServer *http.Server
	startTime  time.Time
}

func NewServer(config *Config) (*Server, error) {
	if config.Port == 0 {
		config.Port = 8080
	}

	if config.Workspace == "" {
		wd, err := os.Getwd()
		if err != nil {
			klog.Fatalf("Failed to get working directory: %v", err)
		}
		config.Workspace = wd
	}

	WorkspaceRoot = config.Workspace
	StartTime = time.Now()

	publicKeyStr := os.Getenv("PICOD_AUTH_PUBLIC_KEY")
	if publicKeyStr == "" {
		klog.Fatalf("PICOD_AUTH_PUBLIC_KEY environment variable is required")
	}

	publicKey, err := parseRSAPublicKey(publicKeyStr)
	if err != nil {
		klog.Fatalf("Failed to parse public key: %v", err)
	}
	PublicKey = publicKey

	gin.SetMode(gin.ReleaseMode)
	router := gin.New()
	router.Use(gin.Logger(), gin.Recovery())

	s := &Server{
		config:    config,
		router:    router,
		startTime: StartTime,
	}

	s.registerRoutes()

	return s, nil
}

func parseRSAPublicKey(keyStr string) (*rsa.PublicKey, error) {
	block, _ := pem.Decode([]byte(keyStr))
	if block == nil {
		return nil, fmt.Errorf("failed to parse PEM block")
	}

	pub, err := x509.ParsePKIXPublicKey(block.Bytes)
	if err != nil {
		return nil, err
	}

	rsaPub, ok := pub.(*rsa.PublicKey)
	if !ok {
		return nil, fmt.Errorf("not an RSA public key")
	}

	return rsaPub, nil
}

func (s *Server) registerRoutes() {
	s.router.GET("/health", s.handleHealth)

	api := s.router.Group("/api")
	api.Use(authMiddleware)
	api.POST("/execute", s.handleExecute)
	api.POST("/files", s.handleUploadFile)
	api.GET("/files", s.handleListFiles)
	api.GET("/files/*path", s.handleDownloadFile)
}

func authMiddleware(c *gin.Context) {
	authHeader := c.GetHeader("Authorization")
	if authHeader == "" {
		c.JSON(http.StatusUnauthorized, ErrorResponse{
			Error:  "Missing authorization header",
			Code:   http.StatusUnauthorized,
			Detail: "Authorization header is required",
		})
		c.Abort()
		return
	}

	parts := strings.Split(authHeader, " ")
	if len(parts) != 2 || parts[0] != "Bearer" {
		c.JSON(http.StatusUnauthorized, ErrorResponse{
			Error:  "Invalid authorization header format",
			Code:   http.StatusUnauthorized,
			Detail: "Expected 'Bearer <token>'",
		})
		c.Abort()
		return
	}

	tokenString := parts[1]

	token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
		if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
			return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
		}
		return PublicKey, nil
	}, jwt.WithExpirationRequired(), jwt.WithIssuedAt(), jwt.WithLeeway(1*time.Minute))

	if err != nil {
		c.JSON(http.StatusUnauthorized, ErrorResponse{
			Error:  "Invalid token",
			Code:   http.StatusUnauthorized,
			Detail: err.Error(),
		})
		c.Abort()
		return
	}

	if !token.Valid {
		c.JSON(http.StatusUnauthorized, ErrorResponse{
			Error:  "Invalid token",
			Code:   http.StatusUnauthorized,
			Detail: "Token validation failed",
		})
		c.Abort()
		return
	}

	c.Next()
}

func (s *Server) handleHealth(c *gin.Context) {
	c.JSON(http.StatusOK, HealthResponse{
		Status:  "ok",
		Service: "PicoD",
		Version: "0.0.1",
		Uptime:  time.Since(StartTime).String(),
	})
}

func (s *Server) handleExecute(c *gin.Context) {
	var req ExecuteRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "Invalid request body",
			Code:  http.StatusBadRequest,
		})
		return
	}

	if len(req.Command) == 0 {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "command cannot be empty",
			Code:  http.StatusBadRequest,
		})
		return
	}

	timeout := DefaultTimeout
	if req.Timeout != "" {
		var err error
		timeout, err = time.ParseDuration(req.Timeout)
		if err != nil {
			c.JSON(http.StatusBadRequest, ErrorResponse{
				Error:  "invalid timeout format",
				Code:   http.StatusBadRequest,
				Detail: err.Error(),
			})
			return
		}
	}

	ctx, cancel := context.WithTimeout(c.Request.Context(), timeout)
	defer cancel()

	cmd := exec.CommandContext(ctx, req.Command[0], req.Command[1:]...)

	if req.WorkingDir != "" {
		workingDir, err := sanitizePath(WorkspaceRoot, req.WorkingDir)
		if err != nil {
			c.JSON(http.StatusBadRequest, ErrorResponse{
				Error: "Invalid working directory: " + err.Error(),
				Code:  http.StatusBadRequest,
			})
			return
		}
		cmd.Dir = workingDir
	} else {
		cmd.Dir = WorkspaceRoot
	}

	if len(req.Env) > 0 {
		cmd.Env = append(os.Environ(), mapToEnvSlice(req.Env)...)
	}

	startTime := time.Now()
	var stdout, stderr strings.Builder
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	err := cmd.Run()
	endTime := time.Now()

	var exitCode int
	var stderrStr string
	if err != nil {
		if ctx.Err() == context.DeadlineExceeded {
			exitCode = TimeoutExitCode
			stderrStr = fmt.Sprintf("command timed out after %d seconds", int(timeout.Seconds()))
		} else {
			if exitErr, ok := err.(*exec.ExitError); ok {
				exitCode = exitErr.ExitCode()
			} else {
				exitCode = 1
			}
			stderrStr = stderr.String()
		}
	} else {
		exitCode = 0
		stderrStr = stderr.String()
	}

	c.JSON(http.StatusOK, ExecuteResponse{
		StdOut:    stdout.String(),
		StdErr:    stderrStr,
		ExitCode:  exitCode,
		Duration:  endTime.Sub(startTime).String(),
		StartTime: startTime.Format(time.RFC3339),
		EndTime:   endTime.Format(time.RFC3339),
	})
}

func mapToEnvSlice(m map[string]string) []string {
	result := make([]string, 0, len(m))
	for k, v := range m {
		result = append(result, fmt.Sprintf("%s=%s", k, v))
	}
	return result
}

func (s *Server) handleUploadFile(c *gin.Context) {
	contentType := c.GetHeader("Content-Type")
	if strings.HasPrefix(contentType, "multipart/form-data") {
		s.handleMultipartUpload(c)
		return
	}

	var req UploadFileRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "Invalid request body",
			Code:  http.StatusBadRequest,
		})
		return
	}

	if req.Path == "" {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "path is required",
			Code:  http.StatusBadRequest,
		})
		return
	}

	if req.Content == "" {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "content is required for JSON upload",
			Code:  http.StatusBadRequest,
		})
		return
	}

	content, err := base64.StdEncoding.DecodeString(req.Content)
	if err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "invalid base64 content",
			Code:  http.StatusBadRequest,
		})
		return
	}

	s.writeFile(c, req.Path, content, req.Mode)
}

func (s *Server) handleMultipartUpload(c *gin.Context) {
	path := c.PostForm("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "path is required",
			Code:  http.StatusBadRequest,
		})
		return
	}

	file, err := c.FormFile("file")
	if err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "file is required",
			Code:  http.StatusBadRequest,
		})
		return
	}

	modeStr := c.PostForm("mode")

	f, err := file.Open()
	if err != nil {
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: "failed to open file",
			Code:  http.StatusInternalServerError,
		})
		return
	}
	defer f.Close()

	content, err := io.ReadAll(f)
	if err != nil {
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: "failed to read file",
			Code:  http.StatusInternalServerError,
		})
		return
	}

	s.writeFile(c, path, content, modeStr)
}

func (s *Server) writeFile(c *gin.Context, path string, content []byte, modeStr string) {
	fullPath, err := sanitizePath(WorkspaceRoot, path)
	if err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "invalid path: " + err.Error(),
			Code:  http.StatusBadRequest,
		})
		return
	}

	dir := filepath.Dir(fullPath)
	if err := os.MkdirAll(dir, WorkspaceRootPerm); err != nil {
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: "failed to create directories",
			Code:  http.StatusInternalServerError,
		})
		return
	}

	mode := parseFileMode(modeStr)
	if err := os.WriteFile(fullPath, content, mode); err != nil {
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: "failed to write file",
			Code:  http.StatusInternalServerError,
		})
		return
	}

	info, err := os.Stat(fullPath)
	if err != nil {
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: "failed to stat file",
			Code:  http.StatusInternalServerError,
		})
		return
	}

	relPath, _ := filepath.Rel(WorkspaceRoot, fullPath)
	c.JSON(http.StatusOK, FileInfo{
		Path:     relPath,
		Size:     info.Size(),
		Modified: info.ModTime().Format(time.RFC3339),
		Mode:     info.Mode().String(),
		IsDir:    info.IsDir(),
	})
}

func (s *Server) handleListFiles(c *gin.Context) {
	path := c.Query("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "Missing 'path' query parameter",
			Code:  http.StatusBadRequest,
		})
		return
	}

	fullPath, err := sanitizePath(WorkspaceRoot, path)
	if err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "invalid path: " + err.Error(),
			Code:  http.StatusBadRequest,
		})
		return
	}

	entries, err := os.ReadDir(fullPath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, ErrorResponse{
				Error: "Directory not found",
				Code:  http.StatusNotFound,
			})
			return
		}
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: "failed to read directory",
			Code:  http.StatusInternalServerError,
		})
		return
	}

	files := make([]FileInfo, 0, len(entries))
	for _, entry := range entries {
		info, err := entry.Info()
		if err != nil {
			continue
		}
		files = append(files, FileInfo{
			Path:     info.Name(),
			Size:     info.Size(),
			Modified: info.ModTime().Format(time.RFC3339),
			Mode:     info.Mode().String(),
			IsDir:    info.IsDir(),
		})
	}

	c.JSON(http.StatusOK, ListFilesResponse{Files: files})
}

func (s *Server) handleDownloadFile(c *gin.Context) {
	requestedPath := c.Param("path")

	fullPath, err := sanitizePath(WorkspaceRoot, requestedPath)
	if err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "access denied: " + err.Error(),
			Code:  http.StatusBadRequest,
		})
		return
	}

	info, err := os.Stat(fullPath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, ErrorResponse{
				Error: "File not found",
				Code:  http.StatusNotFound,
			})
			return
		}
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: "failed to stat file",
			Code:  http.StatusInternalServerError,
		})
		return
	}

	if info.IsDir() {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "Path is a directory, not a file",
			Code:  http.StatusBadRequest,
		})
		return
	}

	c.Header("Content-Description", "File Transfer")
	c.Header("Content-Transfer-Encoding", "binary")
