	SessionExpirationTimeout  = 15 * time.Minute
	RequeueOnParseError       = 30 * time.Second
)

var SandboxGVR = schema.GroupVersionResource{
	Group:    "agents.x-k8s.io",
	Version:  "v1alpha1",
	Resource: "sandboxes",
}

type SandboxReconciler struct {
	dynamicClient dynamic.Interface
	informer      cache.SharedIndexInformer
}

func NewSandboxReconciler() (*SandboxReconciler, error) {
	config, err := getK8sConfig()
	if err != nil {
		return nil, err
	}

	dynamicClient, err := dynamic.NewForConfig(config)
	if err != nil {
		return nil, err
	}

	informer := cache.NewSharedIndexInformer(
		&cache.ListWatch{
			ListFunc: func(options metav1.ListOptions) (runtime.Object, error) {
				return dynamicClient.Resource(SandboxGVR).Namespace(metav1.NamespaceAll).List(context.Background(), options)
			},
			WatchFunc: func(options metav1.ListOptions) (watch.Interface, error) {
				return dynamicClient.Resource(SandboxGVR).Namespace(metav1.NamespaceAll).Watch(context.Background(), options)
			},
		},
		&unstructured.Unstructured{},
		30*time.Second,
		cache.Indexers{},
	)

	return &SandboxReconciler{
		dynamicClient: dynamicClient,
		informer:      informer,
	}, nil
}

func getK8sConfig() (*rest.Config, error) {
	config, err := rest.InClusterConfig()
	if err != nil {
		loadingRules := clientcmd.NewDefaultClientConfigLoadingRules()
		configOverrides := &clientcmd.ConfigOverrides{}
		kubeConfig := clientcmd.NewNonInteractiveDeferredLoadingClientConfig(loadingRules, configOverrides)
		return kubeConfig.ClientConfig()
	}
	return config, nil
}

func (r *SandboxReconciler) Start(stopCh <-chan struct{}) {
	r.informer.Run(stopCh)
	klog.Info("Sandbox informer stopped")
}

func (r *SandboxReconciler) Reconcile(ctx context.Context, namespace, name string) error {
	key := fmt.Sprintf("%s/%s", namespace, name)
	obj, exists, err := r.informer.GetIndexer().GetByKey(key)
	if err != nil {
		klog.Errorf("Failed to get sandbox %s: %v", key, err)
		return err
	}

	if !exists {
		klog.V(4).Infof("Sandbox %s not found, skipping", key)
		return nil
	}

	sandbox := obj.(*unstructured.Unstructured)
	lastActivityStr := sandbox.GetAnnotations()[LastActivityAnnotationKey]
	if lastActivityStr == "" {
		klog.V(4).Infof("Sandbox %s has no last-activity-time annotation, skipping", key)
		return nil
	}

	lastActivity, err := time.Parse(time.RFC3339, lastActivityStr)
	if err != nil {
		klog.Errorf("Failed to parse last-activity-time %s for sandbox %s: %v", lastActivityStr, key, err)
		return err
	}

	expirationTime := lastActivity.Add(SessionExpirationTimeout)
	now := time.Now()

	if now.After(expirationTime) {
		klog.Infof("Sandbox %s is idle for more than %v, deleting", key, SessionExpirationTimeout)
		if err := r.dynamicClient.Resource(SandboxGVR).Namespace(namespace).Delete(ctx, name, metav1.DeleteOptions{}); err != nil {
			if errors.IsNotFound(err) {
				klog.Infof("Sandbox %s already deleted", key)
				return nil
			}
			klog.Errorf("Failed to delete sandbox %s: %v", key, err)
			return err
		}
		klog.Infof("Successfully deleted sandbox %s", key)
		return nil
	}

	klog.V(4).Infof("Sandbox %s will expire in %v", key, expirationTime.Sub(now))
	return nil
}

func (r *SandboxReconciler) AddEventHandler(handler cache.ResourceEventHandler) {
	r.informer.AddEventHandler(handler)
}

