)

func main() {
	klog.InitFlags(nil)
	flag.Parse()

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	reconciler, err := agentd.NewSandboxReconciler()
	if err != nil {
		klog.Fatalf("Failed to create sandbox reconciler: %v", err)
	}

	handler := cache.ResourceEventHandlerFuncs{
		AddFunc: func(obj interface{}) {
			u := obj.(*unstructured.Unstructured)
			if err := reconciler.Reconcile(ctx, u.GetNamespace(), u.GetName()); err != nil {
				klog.Errorf("Failed to reconcile sandbox %s/%s: %v", u.GetNamespace(), u.GetName(), err)
			}
		},
		UpdateFunc: func(oldObj, newObj interface{}) {
			u := newObj.(*unstructured.Unstructured)
			if err := reconciler.Reconcile(ctx, u.GetNamespace(), u.GetName()); err != nil {
				klog.Errorf("Failed to reconcile sandbox %s/%s: %v", u.GetNamespace(), u.GetName(), err)
			}
		},
	}

	reconciler.AddEventHandler(handler)

	stopCh := make(chan struct{})
	go reconciler.Start(stopCh)

	klog.Info("Agentd idle cleanup controller started")

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	<-sigCh
	klog.Info("Received shutdown signal, stopping agentd...")

	close(stopCh)
	klog.Info("Agentd stopped")
}

